mapper.select:
select count(*) from project p where p.project_id = #{projectId} and ( p.owner_id = #{userId} or exists ( select 1 from project_member pm join team_member tm on pm.team_member_id = tm.team_member_id join role_permission rp on pm.role_id = rp.role_id join permission perm on rp.permission_id = perm.permission_id where pm.project_id = p.project_id and tm.user_id = #{userId}
and perm.permission_code = #{permissionCode}
and perm.permission_name = #{permissionName}
and 1 = 0
) )

mapper.sql:
where i.project_id = #{projectId}


	and i.issue_type_id in

		#{issueTypeId}




	and i.version_id in

		#{versionId}






			and (
			i.milestone_id is null


					or i.milestone_id = #{milestoneId}


			)


			and i.milestone_id in

				#{milestoneId}






	and lower(i.title) like '%' || lower(#{keyword}) || '%'



	and i.issue_status_id in

		#{issueStatusId}




	and exists (
	select 1
	from issue_status filter_status
	where filter_status.issue_status_id = i.issue_status_id
	and nvl(filter_status.closed_yn, 'N') = #{closedYn}
	)



	and i.setting_code_id in

		#{settingCodeId}






			and (
			i.assignee_id is null


					or i.assignee_id = #{assigneeId}


			)


			and i.assignee_id in

				#{assigneeId}






	and (



				i.progress_rate between 0 and 20


				i.progress_rate between 21 and 40


				i.progress_rate between 41 and 60


				i.progress_rate between 61 and 80


				i.progress_rate between 81 and 100



	)



	and (
	i.due_date >=
	#{startDate}
	or (i.due_date is null and i.start_date >=
	#{startDate})
	)



	and (
	i.start_date <
	#{dueDate} + 1
	or (i.start_date is null and i.due_date <
	#{dueDate} + 1)
	)

mapper.select:
select /*+ no_merge(paged) leading(paged) use_nl(it) use_nl(ist) use_nl(v) use_nl(sc) use_nl(assignee) use_nl(m) index(it PK_ISSUE_TYPE) index(ist PK_ISSUE_STATUS) index(v IDX_PV_PROJECT_ID) index(sc PK_SETTING_CODE) index(assignee PK_USERS) */ paged.row_no, paged.issue_id, paged.issue_no, '#' || lpad(to_char(paged.issue_no), 4, '0') as display_issue_no, paged.issue_type_id, it.issue_type_name, paged.version_id, v.version_name, paged.milestone_id, m.title as milestone_title, paged.title, paged.issue_status_id, ist.status_name as issue_status_name, ist.closed_yn, paged.setting_code_id, sc.setting_name, paged.assignee_id, assignee.user_name as assignee_name, paged.progress_rate, paged.start_date, paged.due_date, paged.estimated_hours, paged.project_id from ( select rownum as row_no, issue_page.* from ( select
/*+ index_asc(i UK_ISSUE_PROJECT_NO) */
/*+ index_desc(i UK_ISSUE_PROJECT_NO) */
i.issue_id, i.issue_no, i.issue_type_id, i.version_id, i.milestone_id, i.title, i.issue_status_id, i.setting_code_id, i.assignee_id, i.progress_rate, i.start_date, i.due_date, i.estimated_hours, i.project_id from issue i
order by i.issue_no asc
order by i.issue_no desc
) issue_page where rownum <= #{endRow} ) paged left join issue_type it on paged.issue_type_id = it.issue_type_id left join issue_status ist on paged.issue_status_id = ist.issue_status_id left join setting_code sc on paged.setting_code_id = sc.setting_code_id left join users assignee on paged.assignee_id = assignee.user_id left join project_version v on paged.version_id = v.version_id and paged.project_id = v.project_id left join milestone m on paged.milestone_id = m.milestone_id where paged.row_no >= #{startRow} order by paged.row_no asc

select count(*)
from issue_history
where issue_id = #{issueId}

select distinct x.assignee_id, x.assignee_name from ( select u.user_id as assignee_id, u.user_name as assignee_name from project_member pm join team_member tm on pm.team_member_id = tm.team_member_id join users u on tm.user_id = u.user_id where pm.project_id = #{projectId}
union
select owner_user.user_id as assignee_id, owner_user.user_name as assignee_name from project p join users owner_user on p.owner_id = owner_user.user_id where p.project_id = #{projectId} ) x order by x.assignee_name, x.assignee_id

select * from ( select 'ISSUE_TYPE' as option_group, it.issue_type_id, it.issue_type_name, null as issue_status_id, null as issue_status_name, null as version_id, null as version_name, null as setting_code_id, null as setting_name, null as assignee_id, null as assignee_name, null as milestone_id, null as milestone_title, 1 as option_sort from issue_type_project itp join issue_type it on itp.issue_type_id = it.issue_type_id where itp.project_id = #{projectId}
and it.issue_type_id in
#{issueTypeId}
and 1 = 0
union all
select 'ISSUE_STATUS' as option_group, null as issue_type_id, null as issue_type_name, ist.issue_status_id, ist.status_name as issue_status_name, null as version_id, null as version_name, null as setting_code_id, null as setting_name, null as assignee_id, null as assignee_name, null as milestone_id, null as milestone_title, 2 as option_sort from issue_status ist join project p on ist.user_id = p.owner_id where p.project_id = #{projectId}
and ist.issue_status_id in
#{issueStatusId}
and 1 = 0
union all
select 'VERSION' as option_group, null as issue_type_id, null as issue_type_name, null as issue_status_id, null as issue_status_name, pv.version_id, pv.version_name, null as setting_code_id, null as setting_name, null as assignee_id, null as assignee_name, null as milestone_id, null as milestone_title, 3 as option_sort from project_version pv where pv.project_id = #{projectId}
and pv.version_id in
#{versionId}
and 1 = 0
union all
select 'MILESTONE' as option_group, null as issue_type_id, null as issue_type_name, null as issue_status_id, null as issue_status_name, null as version_id, null as version_name, null as setting_code_id, null as setting_name, null as assignee_id, null as assignee_name, m.milestone_id, m.title as milestone_title, 4 as option_sort from milestone m where m.project_id = #{projectId}
and m.milestone_id in
#{milestoneId}
and 1 = 0
union all
select 'MILESTONE' as option_group, null as issue_type_id, null as issue_type_name, null as issue_status_id, null as issue_status_name, null as version_id, null as version_name, null as setting_code_id, null as setting_name, null as assignee_id, null as assignee_name, '__NONE__' as milestone_id, '미지정' as milestone_title, 4 as option_sort from dual
where 1 = 1
where 1 = 0
union all
select 'PRIORITY' as option_group, null as issue_type_id, null as issue_type_name, null as issue_status_id, null as issue_status_name, null as version_id, null as version_name, sc.setting_code_id, sc.setting_name, null as assignee_id, null as assignee_name, null as milestone_id, null as milestone_title, 5 as option_sort from setting_code sc join project p on sc.user_id = p.owner_id where p.project_id = #{projectId} and sc.setting_group_name = 'g002'
and sc.setting_code_id in
#{settingCodeId}
and 1 = 0
union all
select 'ASSIGNEE' as option_group, null as issue_type_id, null as issue_type_name, null as issue_status_id, null as issue_status_name, null as version_id, null as version_name, null as setting_code_id, null as setting_name, x.assignee_id, x.assignee_name, null as milestone_id, null as milestone_title, 6 as option_sort from ( select u.user_id as assignee_id, u.user_name as assignee_name from project_member pm join team_member tm on pm.team_member_id = tm.team_member_id join users u on tm.user_id = u.user_id where pm.project_id = #{projectId}
union
select owner_user.user_id as assignee_id, owner_user.user_name as assignee_name from project p join users owner_user on p.owner_id = owner_user.user_id where p.project_id = #{projectId} ) x
where x.assignee_id in
#{assigneeId}
where 1 = 0
) order by option_sort

mapper.delete:
delete from issue_type_project itp
where itp.project_id = #{projectId}
and exists (
select 1
from issue_type it
where it.issue_type_id = itp.issue_type_id
and it.user_id = #{userId}
)
and not exists (
select 1
from issue i
where i.project_id = itp.project_id
and i.issue_type_id = itp.issue_type_id
)

	and itp.issue_type_id not in

		#{issueTypeId}

mapper.select:
select count(*)
from issue i
join project p
on i.project_id = p.project_id
where i.project_id = #{projectId}
and i.issue_id = #{issueId}
and (
p.owner_id = #{userId}
or exists (
select 1
from project_member pm
join team_member tm
on pm.team_member_id = tm.team_member_id
join role_permission rp
on pm.role_id = rp.role_id
join permission perm
on rp.permission_id = perm.permission_id
where pm.project_id = p.project_id
and tm.user_id = #{userId}
and perm.permission_code = #{updatePermissionCode}
)
or (
i.assignee_id = #{userId}
and exists (
select 1
from project_member pm
join team_member tm
on pm.team_member_id = tm.team_member_id
join role_permission rp
on pm.role_id = rp.role_id
join permission perm
on rp.permission_id = perm.permission_id
where pm.project_id = p.project_id
and tm.user_id = #{userId}
and perm.permission_code = #{updateOwnPermissionCode}
)
)
)

